-- STEP 1: query [fylker]
SELECT fylkesnummer FROM fylker_a60155918c4a47c2b78f4ab52fc2bfa4.fylke WHERE fylkesnavn ILIKE '%Finnmark%';

-- STEP BOUNDARY --

-- STEP 2: query [kommuner]
SELECT kommunenummer, omrade FROM kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE kommunenummer LIKE '56%';

-- STEP BOUNDARY --

-- STEP 3: query [flomsoner]
SELECT b.kommunenummer, COUNT(*) AS building_count FROM flomsoner_627ee106072240e99d2b21ec4717bf01.flomsoner fs JOIN matrikkelenbygning_627ee106072240e99d2b21ec4717bf01.bygning b ON ST_Intersects(fs.omrade, b.geometri) WHERE fs.returnperiod = '200' AND b.kommunenummer IN ('5614', '5601', '5605', '5603', '5616') GROUP BY b.kommunenummer;
